package config
import ( "os" "time"
"github.com/joho/godotenv" "github.com/sirupsen/logrus" )
const ( ServiceName = "ledger-command-service" DefaultPort = "8080" APIBasePath = "/api" GracefulStopTimeout = 10 * time.Second DBMigrationsDir = "internal/migrations" )
type Config struct { ServiceName string Host string Port string Environment string LogLevel string
DBHost string DBPort string DBUser string DBPassword string DBName string DBSSLMode string DBConns int
KafkaBootstrapServers string KafkaTopic string
RedisHost string RedisPort string }
func Load() *Config { filename := "./files/.env" if _, err := os.Stat(filename); err == nil { _ = godotenv.Load(filename) } else { _ = godotenv.Load(".env") }
cfg := &Config{ ServiceName: ServiceName, Host: getEnv("HOST", ""), Port: getEnv("PORT", DefaultPort), Environment: getEnv("ENVIRONMENT", "local"), LogLevel: getEnv("LOG_LEVEL", "debug"),
DBHost: getEnv("LEDGER_DB_HOST", "localhost"), DBPort: getEnv("LEDGER_DB_PORT", "5432"), DBUser: getEnv("LEDGER_DB_USERNAME", "ledger"), DBPassword: getEnv("LEDGER_DB_PASSWORD", "ledger"), DBName: getEnv("LEDGER_DB_NAME", "ledger"), DBSSLMode: getEnv("LEDGER_DB_SSL_MODE", "disable"), DBConns: 10,
KafkaBootstrapServers: getEnv("LEDGER_KAFKA_BOOTSTRAP_SERVERS", "localhost:9092"), KafkaTopic: getEnv("LEDGER_KAFKA_TOPIC", "ledger.events"),
RedisHost: getEnv("LEDGER_REDIS_HOST", "localhost"), RedisPort: getEnv("LEDGER_REDIS_PORT", "6379"), }
lvl, err := logrus.ParseLevel(cfg.LogLevel) if err != nil { lvl = logrus.DebugLevel } logrus.SetLevel(lvl) logrus.SetFormatter(&logrus.JSONFormatter{})
return cfg }
func getEnv(key, fallback string) string { if val := os.Getenv(key); val != "" { return val } return fallback }

package domain

import "time"

// EventType represents the type of a ledger domain event.
type EventType string

const (
	EventAccountCreated      EventType = "ACCOUNT_CREATED"
	EventAccountCredited     EventType = "ACCOUNT_CREDITED"
	EventAccountDebited      EventType = "ACCOUNT_DEBITED"
	EventAccountStatusChanged EventType = "ACCOUNT_STATUS_CHANGED"
	EventTransferInitiated   EventType = "TRANSFER_INITIATED"
	EventTransferCompleted   EventType = "TRANSFER_COMPLETED"
	EventTransferReversed    EventType = "TRANSFER_REVERSED"
)

// AccountStatus represents the lifecycle state of an account.
type AccountStatus string

const (
	StatusActive AccountStatus = "ACTIVE"
	StatusFrozen AccountStatus = "FROZEN"
	StatusClosed AccountStatus = "CLOSED"
)

// TransactionDirection for filtering purposes.
type TransactionDirection string

const (
	DirectionCredit TransactionDirection = "CREDIT"
	DirectionDebit  TransactionDirection = "DEBIT"
)

// LedgerEvent is the persisted domain event stored in the event store.
type LedgerEvent struct {
	ID          string    `bun:"id,pk"`
	AggregateID string    `bun:"aggregate_id,notnull"`
	Version     int64     `bun:"version,notnull"`
	EventType   EventType `bun:"event_type,notnull"`
	Payload     []byte    `bun:"payload,type:jsonb,notnull"`
	CreatedAt   time.Time `bun:"created_at,notnull,default:now()"`
}

func (LedgerEvent) TableName() string { return "ledger_events" }

// OutboxEntry is the transactional outbox record that Debezium/CDC will relay to Kafka.
type OutboxEntry struct {
	ID          string    `bun:"id,pk"`
	AggregateID string    `bun:"aggregate_id,notnull"`
	EventType   string    `bun:"event_type,notnull"`
	Payload     []byte    `bun:"payload,type:jsonb,notnull"`
	CreatedAt   time.Time `bun:"created_at,notnull,default:now()"`
	Processed   bool      `bun:"processed,notnull,default:false"`
}

func (OutboxEntry) TableName() string { return "outbox" }

// IdempotencyRecord stores the result of a previously processed command.
type IdempotencyRecord struct {
	Key        string    `bun:"key,pk"`
	StatusCode int       `bun:"status_code,notnull"`
	Response   []byte    `bun:"response,type:jsonb"`
	CreatedAt  time.Time `bun:"created_at,notnull,default:now()"`
}

func (IdempotencyRecord) TableName() string { return "idempotency_keys" }

package kafka

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/segmentio/kafka-go"
	"github.com/sirupsen/logrus"
	"go-ledger/internal/domain"
)

// Producer wraps a kafka-go writer.
type Producer struct {
	writer *kafka.Writer
}

// NewProducer creates a new Kafka producer for the given bootstrap servers and topic.
func NewProducer(bootstrapServers, topic string) *Producer {
	w := &kafka.Writer{
		Addr:         kafka.TCP(bootstrapServers),
		Topic:        topic,
		Balancer:     &kafka.LeastBytes{},
		RequiredAcks: kafka.RequireOne,
		MaxAttempts:  3,
		WriteTimeout: 10 * time.Second,
		ReadTimeout:  10 * time.Second,
	}
	return &Producer{writer: w}
}

// PublishEvent serializes and writes a LedgerEvent to Kafka.
func (p *Producer) PublishEvent(ctx context.Context, event *domain.LedgerEvent) error {
	payload, err := json.Marshal(event)
	if err != nil {
		return fmt.Errorf("kafka producer: marshal event: %w", err)
	}

	msg := kafka.Message{
		Key:   []byte(event.AggregateID),
		Value: payload,
		Headers: []kafka.Header{
			{Key: "event-type", Value: []byte(event.EventType)},
		},
		Time: event.CreatedAt,
	}

	if err := p.writer.WriteMessages(ctx, msg); err != nil {
		logrus.WithError(err).WithField("aggregate_id", event.AggregateID).
			Error("kafka: failed to publish event")
		return fmt.Errorf("kafka producer: write: %w", err)
	}

	logrus.WithFields(logrus.Fields{
		"aggregate_id": event.AggregateID,
		"event_type":   event.EventType,
		"version":      event.Version,
	}).Info("kafka: event published")

	return nil
}

// Close closes the underlying writer.
func (p *Producer) Close() error {
	return p.writer.Close()
}

package repository

import (
	"context"
	"database/sql"
	"errors"
	"fmt"

	"github.com/uptrace/bun"
	"go-ledger/internal/domain"
)

type accountDB struct {
	db *bun.DB
}

// NewAccountRepository creates a new PostgreSQL-backed account repository.
func NewAccountRepository(db *bun.DB) AccountRepository {
	return &accountDB{db: db}
}

func (r *accountDB) GetByID(ctx context.Context, id string) (*domain.Account, error) {
	account := &domain.Account{}
	err := r.db.NewSelect().Model(account).Where("id = ?", id).Scan(ctx)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, fmt.Errorf("account %s not found", id)
		}
		return nil, fmt.Errorf("account repository: get by id: %w", err)
	}
	return account, nil
}

func (r *accountDB) Save(ctx context.Context, account *domain.Account) error {
	_, err := r.db.NewInsert().Model(account).
		On("CONFLICT (id) DO UPDATE").
		Set("balance = EXCLUDED.balance").
		Set("status = EXCLUDED.status").
		Set("version = EXCLUDED.version").
		Set("updated_at = EXCLUDED.updated_at").
		Exec(ctx)
	if err != nil {
		return fmt.Errorf("account repository: save: %w", err)
	}
	return nil
}

package repository

import (
	"context"
	"database/sql"
	"errors"
	"fmt"

	"github.com/uptrace/bun"
	"go-ledger/internal/domain"
)

type eventStoreDB struct {
	db *bun.DB
}

// NewEventStoreRepository creates a new PostgreSQL-backed event store.
func NewEventStoreRepository(db *bun.DB) EventStoreRepository {
	return &eventStoreDB{db: db}
}

func (r *eventStoreDB) AppendEvent(ctx context.Context, event *domain.LedgerEvent) error {
	_, err := r.db.NewInsert().Model(event).Exec(ctx)
	if err != nil {
		return fmt.Errorf("event store: append event: %w", err)
	}
	return nil
}

func (r *eventStoreDB) GetEventsByAggregateID(ctx context.Context, aggregateID string) ([]*domain.LedgerEvent, error) {
	var events []*domain.LedgerEvent
	err := r.db.NewSelect().
		Model(&events).
		Where("aggregate_id = ?", aggregateID).
		OrderExpr("version ASC").
		Scan(ctx)
	if err != nil {
		return nil, fmt.Errorf("event store: get events: %w", err)
	}
	return events, nil
}

func (r *eventStoreDB) GetCurrentVersion(ctx context.Context, aggregateID string) (int64, error) {
	var version sql.NullInt64
	err := r.db.NewSelect().
		TableExpr("ledger_events").
		ColumnExpr("MAX(version)").
		Where("aggregate_id = ?", aggregateID).
		Scan(ctx, &version)
	if err != nil && !errors.Is(err, sql.ErrNoRows) {
		return 0, fmt.Errorf("event store: get version: %w", err)
	}
	if !version.Valid {
		return 0, nil
	}
	return version.Int64, nil
}

package repository

import (
	"context"
	"database/sql"
	"errors"
	"fmt"

	"github.com/uptrace/bun"
	"go-ledger/internal/domain"
)

type idempotencyDB struct {
	db *bun.DB
}

// NewIdempotencyRepository creates a new PostgreSQL-backed idempotency repository.
func NewIdempotencyRepository(db *bun.DB) IdempotencyRepository {
	return &idempotencyDB{db: db}
}

func (r *idempotencyDB) Get(ctx context.Context, key string) (*domain.IdempotencyRecord, error) {
	record := &domain.IdempotencyRecord{}
	err := r.db.NewSelect().Model(record).Where("key = ?", key).Scan(ctx)
	if err != nil {
		if errors.Is(err, sql.ErrNoRows) {
			return nil, nil // not found – new request
		}
		return nil, fmt.Errorf("idempotency: get: %w", err)
	}
	return record, nil
}

func (r *idempotencyDB) Save(ctx context.Context, record *domain.IdempotencyRecord) error {
	_, err := r.db.NewInsert().Model(record).
		On("CONFLICT (key) DO NOTHING").
		Exec(ctx)
	if err != nil {
		return fmt.Errorf("idempotency: save: %w", err)
	}
	return nil
}

package repository

import (
	"context"
	"go-ledger/internal/domain"
)

// EventStoreRepository persists immutable domain events.
type EventStoreRepository interface {
	// AppendEvent writes an event with optimistic locking (unique constraint on aggregate_id + version).
	AppendEvent(ctx context.Context, event *domain.LedgerEvent) error
	// GetEventsByAggregateID returns all events for an aggregate ordered by version ascending.
	GetEventsByAggregateID(ctx context.Context, aggregateID string) ([]*domain.LedgerEvent, error)
	// GetCurrentVersion returns the latest version number for an aggregate (0 if none).
	GetCurrentVersion(ctx context.Context, aggregateID string) (int64, error)
}

// OutboxRepository writes outbox entries in the same transaction as the event.
type OutboxRepository interface {
	InsertOutbox(ctx context.Context, entry *domain.OutboxEntry) error
}

// AccountRepository provides read access to the write-side account state (materialized from events).
type AccountRepository interface {
	GetByID(ctx context.Context, id string) (*domain.Account, error)
	Save(ctx context.Context, account *domain.Account) error
}

// IdempotencyRepository deduplicates incoming commands by their Idempotency-Key header.
type IdempotencyRepository interface {
	Get(ctx context.Context, key string) (*domain.IdempotencyRecord, error)
	Save(ctx context.Context, record *domain.IdempotencyRecord) error
}

package repository

import (
	"context"
	"fmt"

	"github.com/uptrace/bun"
	"go-ledger/internal/domain"
)

type outboxDB struct {
	db *bun.DB
}

// NewOutboxRepository creates a new PostgreSQL-backed outbox repository.
func NewOutboxRepository(db *bun.DB) OutboxRepository {
	return &outboxDB{db: db}
}

func (r *outboxDB) InsertOutbox(ctx context.Context, entry *domain.OutboxEntry) error {
	_, err := r.db.NewInsert().Model(entry).Exec(ctx)
	if err != nil {
		return fmt.Errorf("outbox: insert: %w", err)
	}
	return nil
}
